// Server's copy of the catalog — source of truth for prices AND variant
// identifiers. Never trust prices or variant selections coming from the
// browser; always resolve them against this file.
//
// Every color/size combination actually sellable on Printful is listed here
// (per the user's request to show the full Printful color range, not a
// curated on-brand subset).
//
// PRICING: price depends on SIZE, not on the design — same schedule across
// the whole catalog. Shipping is a flat fee, waived above the free-shipping
// threshold.
//
// printify_variant_id is still null everywhere — fill it in once each design
// is also synced on Printify. printify_product_id is per-product.

const BOA_SHIPPING_FLAT_CENTS = 475;
const BOA_FREE_SHIPPING_THRESHOLD_CENTS = 8500;

function boa_price_cents_for_size(string $size): int
{
    return match ($size) {
        '2XL' => 3699,
        '3XL' => 3999,
        '4XL' => 4099,
        default => 3499, // S, M, L, XL
    };
}

// Computes the shipping fee for a given subtotal, in cents.
function boa_shipping_cents(int $subtotalCents): int
{
    if ($subtotalCents <= 0) {
        return 0;
    }
    return $subtotalCents >= BOA_FREE_SHIPPING_THRESHOLD_CENTS ? 0 : BOA_SHIPPING_FLAT_CENTS;
}

